	private void addRepeatedStartDrivers(int count) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI start = vf.createIRI(EX, "start");
			IRI a = vf.createIRI(EX, "a");
			for (int driver = 1; driver <= count; driver++) {
				conn.add(vf.createIRI(EX, "driver" + driver), start, a);
			}
		}
	}

