	@Test
	public void parallelFrontierPreservesDeterministicSetSemantics() throws Exception {
		long[][] edges = {
				{ 10L, 20L }, { 10L, 30L }, { 10L, 40L }, { 10L, 50L },
				{ 20L, 60L }, { 20L, 70L }, { 20L, 10L },
				{ 30L, 60L }, { 30L, 80L }, { 30L, 30L },
				{ 40L, 70L }, { 40L, 90L },
				{ 50L, 60L }, { 50L, 90L },
				{ 60L, 100L }, { 70L, 100L }, { 80L, 110L }, { 90L, 110L },
				{ 100L, 10L }
		};
		PathGraphSource serial = new PathGraphSource(edges);
		PathGraphSource parallel = new PathGraphSource(edges);
		String previousEnabled = System.getProperty(PARALLEL_ENABLED);
		String previousThreads = System.getProperty(PARALLEL_THREADS);
		String previousMaxTasks = System.getProperty(PARALLEL_MAX_TASKS);
		String previousParallelMin = System.getProperty(PATH_FRONTIER_PARALLEL_MIN);
		List<Long> serialRows;
		List<Long> parallelRows;
		try {
			System.setProperty(PARALLEL_ENABLED, "false");
			serialRows = pathRows(serial);
			System.setProperty(PARALLEL_ENABLED, "true");
			System.setProperty(PARALLEL_THREADS, "3");
			System.setProperty(PARALLEL_MAX_TASKS, "3");
			System.setProperty(PATH_FRONTIER_PARALLEL_MIN, "2");
			parallelRows = pathRows(parallel);
		} finally {
			restoreProperty(PARALLEL_ENABLED, previousEnabled);
			restoreProperty(PARALLEL_THREADS, previousThreads);
			restoreProperty(PARALLEL_MAX_TASKS, previousMaxTasks);
			restoreProperty(PATH_FRONTIER_PARALLEL_MIN, previousParallelMin);
		}

		assertThat(serialRows).containsExactly(20L, 30L, 40L, 50L, 10L, 60L, 70L, 80L, 90L, 100L, 110L);
		assertThat(parallelRows)
				.as("per-worker deltas must merge at each level in deterministic ascending SET order")
				.containsExactlyElementsOf(serialRows)
				.doesNotHaveDuplicates();
		assertThat(parallel.parallelSourceOpens)
				.as("wide frontiers must use independent same-snapshot worker sources")
				.hasValue(3);
		assertThat(parallel.parallelSourceCloses)
				.as("every same-snapshot worker source must close after the level group terminates")
				.hasValue(3);
	}

	private static List<Long> pathRows(PathGraphSource source) throws IOException {
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("start", 0, "target", 1), null);
		layout.freeze(List.of("start", "target"));
		RowState row = new RowState(source, layout, new QueryBindingSet());
		Arrays.fill(row.slots, NativeLmdbQuerySource.UNKNOWN_ID);
		row.slots[0] = 10L;
		row.recomputeBoundMask();
		PatternPlan step = new PatternPlan(Term.slot(0), Term.constant(PathGraphSource.PREDICATE), Term.slot(1),
				Term.unbound(), ContextConstraint.UNRESTRICTED, false, source.edges.length);
		PathPlan path = new PathPlan(step, 0, NativeLmdbQuerySource.UNKNOWN_ID, 1,
				NativeLmdbQuerySource.UNKNOWN_ID, TripleIndex.SUBJ_IDX, TripleIndex.OBJ_IDX, false);
		List<Long> rows = new ArrayList<>();
		try (RowCursor cursor = path.open(row)) {
			while (cursor.next()) {
				rows.add(row.slots[1]);
			}
		}
		return rows;
	}

	private static void restoreProperty(String property, String previous) {
		if (previous == null) {
			System.clearProperty(property);
		} else {
			System.setProperty(property, previous);
		}
	}

	@Test
	public void laterValuesTargetsStopPathAfterFirstExpansion() throws Exception {
		PathGraphSource source = new PathGraphSource(new long[][] {
				{ 10L, 20L }, { 10L, 30L }, { 20L, 40L }, { 30L, 50L }
		});
		SingletonSet telemetry = new SingletonSet();
		telemetry.setRuntimeTelemetryEnabled(true);
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("start", 0, "target", 1), null);
		layout.freeze(List.of("start", "target"));
		RowState row = new RowState(source, layout, new QueryBindingSet(), telemetry);
		Arrays.fill(row.slots, NativeLmdbQuerySource.UNKNOWN_ID);
		row.slots[0] = 10L;
		row.recomputeBoundMask();
		PatternPlan step = new PatternPlan(Term.slot(0), Term.constant(PathGraphSource.PREDICATE), Term.slot(1),
				Term.unbound(), ContextConstraint.UNRESTRICTED, false, 4D);
		PathPlan path = new PathPlan(step, 0, NativeLmdbQuerySource.UNKNOWN_ID, 1,
				NativeLmdbQuerySource.UNKNOWN_ID, TripleIndex.SUBJ_IDX, TripleIndex.OBJ_IDX, false);
		ValuesPlan targets = new ValuesPlan(new ValuesRow[] {
				new ValuesRow(new int[] { 1 }, new long[] { 20L })
		});

		int rows = 0;
		try (RowCursor cursor = new JoinPlan(path, targets).open(row)) {
			while (cursor.next()) {
				rows++;
			}
		}

		assertThat(rows).isOne();
		assertThat(source.pathStepCalls)
				.as("the sole admissible target is found while expanding the start node")
				.hasValue(1);
		assertThat(telemetry.getLongMetricActual("nativePathExpansionsActual")).isEqualTo(1L);
		assertThat(telemetry.getLongMetricActual("nativePathTargetCutoffsActual")).isEqualTo(1L);
		assertThat(telemetry.getLongMetricActual("nativePathTargetsActual")).isEqualTo(1L);
	}

